def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        base = np.tanh(item / (cap + 1e-5)) + 1.0
        complexity = 0.0
        scaling = 1.0
        decay = 0.0
        for m in range(1, 15):
            if m % 4 == 0:
                scaling *= (1.02 + 0.008 * m)
            elif m % 7 == 0:
                scaling /= (1.01 + 0.005 * m)
            temp_val = np.abs(np.sin(item * m) - np.cos(cap / (m + 1)))
            if temp_val > 0.5:
                val = np.log1p(temp_val * m) / (m + 2)
            else:
                val = (temp_val ** 3 + m) / (1 + temp_val)
            complexity += val * scaling
            if (cap + m) % (item + m) == 0 or (int(cap) * m) % (int(item) + 1) == 0:
                complexity *= 1.03
            else:
                complexity *= 0.97
            if m == 7:
                for n in range(1, 6):
                    diff = item * n - cap / (n + 1)
                    if diff < 0:
                        decay += np.exp(-abs(diff)) / (n + 2)
                    else:
                        decay -= np.log1p(diff) / (n + 3)
            if cap % 3 == m % 5:
                complexity += np.sin(m * cap / (item + 1)) * 0.4
            else:
                complexity -= np.cos(m * item / (cap + 1)) * 0.3
        complexity += decay * 0.7
        if complexity < 0:
            priority = -complexity * np.sqrt(cap + item)
        else:
            priority = complexity / (cap + item + 1)
        priority *= base
        if item / cap > 1.2:
            priority *= 1.2
        elif item / cap < 0.3:
            priority *= 0.8
        remainder = cap % (int(item) + 2)
        if remainder == 0:
            priority *= 0.95
        elif remainder % 2 == 0:
            priority *= 1.05
        if np.isclose(item, cap, atol=0.1):
            priority *= 1.1
        elif abs(item - cap) > cap * 0.5:
            priority *= 0.9
        priorities[i] = priority
    return priorities
